// Generated by OrchestKit Claude Plugin
// Created: 2026-07-17

// Pure ranking helpers shared by the docs search paths:
//   • app/api/search (Orama/fumadocs) — post-search rerank of page blocks
//   • lib/doc-search (NLWeb /ask + MCP) — lightweight index scoring
//   • components/search-dialog — grouped display (see lib/search-display)
//
// Ranking rules:
//   1. Per-property boosts: title > description/headings > body (applied at
//      the scorer, see doc-search.ts and the route's Orama boost config).
//   2. Doc-type weighting: guide / concept / cookbook rank ABOVE reference.
//   3. Exact-title floor: a query that exactly or prefix-matches a page title
//      overrides type weighting — that page must surface in the top 3.

export type DocType =
	| "guide"
	| "concept"
	| "cookbook"
	| "skill"
	| "agent"
	| "hook"
	| "reference"
	| "other";

/** Classify a docs URL into a ranking doc-type. */
export function docTypeForUrl(url: string): DocType {
	if (url.startsWith("/docs/reference/skills")) return "skill";
	if (url.startsWith("/docs/reference/agents")) return "agent";
	if (url.startsWith("/docs/reference/hooks")) return "hook";
	if (url.startsWith("/docs/reference")) return "reference";
	if (url.startsWith("/docs/cookbook")) return "cookbook";
	if (
		url.startsWith("/docs/guides") ||
		url.startsWith("/docs/getting-started") ||
		url.startsWith("/docs/troubleshooting")
	)
		return "guide";
	if (
		url.startsWith("/docs/foundations") ||
		url.startsWith("/docs/memory") ||
		url.startsWith("/docs/skills") ||
		url.startsWith("/docs/agents") ||
		url.startsWith("/docs/hooks")
	)
		return "concept";
	return "other";
}

/** Multiplier applied to relevance. guide/concept/cookbook > reference. */
export const DOC_TYPE_WEIGHT: Record<DocType, number> = {
	guide: 1.35,
	concept: 1.3,
	cookbook: 1.25,
	other: 1.0,
	skill: 0.9,
	agent: 0.9,
	hook: 0.9,
	reference: 0.8,
};

/** Normalize for title comparison: lowercase, strip "/ork:" and a leading
 * article, collapse whitespace. */
function normTitle(s: string): string {
	return s
		.toLowerCase()
		.replace(/^\/?ork:/, "")
		.replace(/^(the|a|an)\s+/, "")
		.replace(/\s+/g, " ")
		.trim();
}

export const EXACT_TITLE_BONUS = 2000;
export const PREFIX_TITLE_BONUS = 1000;

/**
 * Exact-title floor. Large additive bonus that overrides doc-type weighting:
 * "commit" must surface the /ork:commit reference page in the top 3 even
 * though reference pages carry the lowest type weight.
 */
export function titleMatchBonus(query: string, title: string): number {
	const q = normTitle(query);
	if (!q) return 0;
	const t = normTitle(title);
	if (t === q) return EXACT_TITLE_BONUS;
	// Prefix on the normalized title, or on its concatenated form so
	// "worktree" prefix-matches the "WorktreeCreate" hook page.
	const qFlat = q.replace(/[\s-]/g, "");
	const tFlat = t.replace(/[\s-]/g, "");
	if (t.startsWith(q) || tFlat.startsWith(qFlat)) return PREFIX_TITLE_BONUS;
	return 0;
}

/** Orama typo tolerance: enabled only for queries of 4+ characters. */
export function typoToleranceFor(query: string): 0 | 1 {
	return query.trim().length >= 4 ? 1 : 0;
}

/** Truncate a query for the zero-result analytics beacon (max 80 chars). */
export function truncateQuery(query: string, max = 80): string {
	return query.trim().slice(0, max);
}

export function stripOrigin(url: string): string {
	return url.replace(/^https?:\/\/[^/]+/, "");
}

/**
 * Rerank already-relevance-sorted page blocks. Position is used as the base
 * relevance signal (Orama scores are not exposed by fumadocs), scaled by
 * doc-type weight, with the exact-title floor added on top.
 */
export function rerankByRelevance<T extends { url: string; title: string }>(
	blocks: readonly T[],
	query: string,
): T[] {
	const n = blocks.length;
	return blocks
		.map((block, i) => ({
			block,
			score:
				(n - i) * DOC_TYPE_WEIGHT[docTypeForUrl(stripOrigin(block.url))] +
				titleMatchBonus(query, block.title),
		}))
		.sort((a, b) => b.score - a.score)
		.map((s) => s.block);
}
